using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train model at startup (small dataset — runs quickly)
var loggerFactory = LoggerFactory.Create(b => b.AddConsole());
var trainer = new ModelTrainingService(
    loggerFactory.CreateLogger<ModelTrainingService>(),
    builder.Configuration);
trainer.TrainAndEvaluate();

// Register pooled prediction engine (thread-safe for ASP.NET Core)
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

// Register label names for score mapping
builder.Services.AddSingleton(new LabelRegistry(trainer.Labels));

var app = builder.Build();
app.MapControllers();
app.Run();

